import{_ as l,C as n,o as s,c as o,E as a,w as r,a as i,a0 as d}from"./chunks/framework.CkNTPv-z.js";const f=JSON.parse('{"title":"Slovenia Healthcare & HRT","description":"Transgender healthcare access in Slovenia","frontmatter":{"layout":"doc","title":"Slovenia Healthcare & HRT","description":"Transgender healthcare access in Slovenia"},"headers":[],"relativePath":"europe/slovenia/healthcare.md","filePath":"europe/slovenia/healthcare.md","lastUpdated":null}'),c={name:"europe/slovenia/healthcare.md"};function h(u,e,p,g,b,m){const t=n("Badge");return s(),o("div",null,[a(t,{variant:"yellow"},{default:r(()=>[...e[0]||(e[0]=[i("Gatekeeping Model",-1)])]),_:1}),a(t,{variant:"yellow"},{default:r(()=>[...e[1]||(e[1]=[i("University Medical Centre Ljubljana",-1)])]),_:1}),a(t,{variant:"green"},{default:r(()=>[...e[2]||(e[2]=[i("Public Healthcare (ZZZS)",-1)])]),_:1}),e[3]||(e[3]=d('<h1 id="healthcare-hrt-in-slovenia" tabindex="-1">Healthcare &amp; HRT in Slovenia <a class="header-anchor" href="#healthcare-hrt-in-slovenia" aria-label="Permalink to &quot;Healthcare &amp; HRT in Slovenia&quot;">​</a></h1><h2 id="gatekeeping-model" tabindex="-1">Gatekeeping Model <a class="header-anchor" href="#gatekeeping-model" aria-label="Permalink to &quot;Gatekeeping Model&quot;">​</a></h2><p>Slovenia operates a <strong>gatekeeping model</strong> for transgender healthcare:</p><ul><li><strong>Psychiatric diagnosis required</strong> to access HRT</li><li>Treatment centralized at the <strong>University Medical Centre Ljubljana</strong> (UKCL)</li><li>Multidisciplinary team involved in treatment decisions</li><li>Public healthcare covers most costs</li></ul><h2 id="accessing-hrt" tabindex="-1">Accessing HRT <a class="header-anchor" href="#accessing-hrt" aria-label="Permalink to &quot;Accessing HRT&quot;">​</a></h2><h3 id="step-1-referral" tabindex="-1">Step 1: Referral <a class="header-anchor" href="#step-1-referral" aria-label="Permalink to &quot;Step 1: Referral&quot;">​</a></h3><ul><li>Contact a GP or directly reach the <strong>University Medical Centre Ljubljana</strong>, Department of Psychiatry</li><li>Referral from a GP is the standard pathway</li><li>Initial appointment wait time: 2-4 months</li></ul><h3 id="step-2-psychiatric-assessment" tabindex="-1">Step 2: Psychiatric Assessment <a class="header-anchor" href="#step-2-psychiatric-assessment" aria-label="Permalink to &quot;Step 2: Psychiatric Assessment&quot;">​</a></h3><ul><li>3-5 sessions with a psychiatrist specializing in gender dysphoria</li><li>Diagnosis per ICD-10/11 criteria</li><li>Psychological evaluation and treatment planning</li></ul><h3 id="step-3-hormone-therapy" tabindex="-1">Step 3: Hormone Therapy <a class="header-anchor" href="#step-3-hormone-therapy" aria-label="Permalink to &quot;Step 3: Hormone Therapy&quot;">​</a></h3><ul><li>Referral to an endocrinologist at UKCL</li><li>Baseline blood tests for hormone levels</li><li>HRT prescribed under medical supervision</li><li>Follow-up every 3-6 months initially</li><li>Annual monitoring thereafter</li></ul><h2 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th></tr></thead><tbody><tr><td>University Medical Centre Ljubljana</td><td>Ljubljana</td><td>Full gender clinic (public)</td></tr><tr><td>Maribor University Medical Centre</td><td>Maribor</td><td>Limited gender services</td></tr><tr><td>Private psychiatrists</td><td>Ljubljana</td><td>Assessment (shorter wait times, €70-120)</td></tr><tr><td>Private endocrinologists</td><td>Ljubljana, Maribor</td><td>HRT (limited trans experience)</td></tr></tbody></table><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><ul><li><strong>EU prescriptions</strong>: Valid in Slovenia under EU mutual recognition</li><li><strong>Non-EU prescriptions</strong>: Must be evaluated by a Slovenian doctor</li><li><strong>Importing medication</strong>: 3-month supply permitted with a doctor&#39;s letter</li><li><strong>Keep in original packaging</strong> with prescription labels</li><li><strong>Pharmacies</strong>: Lekarna (national chain) stocks standard HRT medications</li><li><strong>Generic names</strong>: Know your medications (estradiol, cyproterone, testosterone)</li></ul><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><ul><li>Gender-affirming surgeries are <strong>covered by public healthcare</strong> (ZZZS)</li><li>Authorization requires diagnosis + documented HRT period (typically 1-2 years)</li><li>Surgery is performed abroad through public funding agreements (usually in Serbia or Germany)</li><li>Alternative: self-funded surgery abroad</li><li>Top surgery: covered through public system or private (€4,000-7,000)</li><li>Bottom surgery: available through public funding abroad</li><li>Facial feminization: generally not covered by public healthcare</li></ul><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Public (insured)</th><th>Private</th></tr></thead><tbody><tr><td>Psychiatric assessment</td><td>Free (public)</td><td>€70-120</td></tr><tr><td>Endocrinology visit</td><td>Free (public)</td><td>€60-100</td></tr><tr><td>HRT (monthly)</td><td>€5-20</td><td>€20-40</td></tr><tr><td>Gender clinic (UKCL)</td><td>Free (public)</td><td>N/A</td></tr><tr><td>Top surgery</td><td>Covered (public)</td><td>€4,000-7,000</td></tr></tbody></table><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.kclj.si/" target="_blank" rel="noreferrer">University Medical Centre Ljubljana</a></li><li><a href="https://www.zzzs.si/" target="_blank" rel="noreferrer">ZZZS (Health Insurance Institute)</a></li><li><a href="https://www.legebitra.si/" target="_blank" rel="noreferrer">Legebitra (LGBTQ+ Organization)</a></li><li><a href="https://transakcija.si/" target="_blank" rel="noreferrer">TransAkcija</a></li></ul>',21))])}const v=l(c,[["render",h]]);export{f as __pageData,v as default};
